var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('d23')._controlBehavior, l = g._getColumnOrder('stt_rec_hd');
var e = (v ? 'Thông tin mã khách của chứng từ phải giống với hóa đơn dịch vụ.' : 'Services Sale Return Invoice should have same customer information as Service Invoice.');
var t = f.getItemValue('ma_kh');
for (var i = 1; i <= g._rowCount; i++) {
  if (g._getItemValue(i, l) {
    var u = g._getItem(i, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(id);
      $message.show(e, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
      f._checked = false;
      break;
    }
  }
}
