script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', null, null, 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._action == 'New') f.setItemValues('ma_mau_ct, ten_mau_ct%l', [f._voucherTemplate, f._voucherTemplateName]);
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d23')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d23')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt:t_tien2,t_thue,t_tt');
    if (!f._udfQuantityPrice) v.addGridFields(g, 'tien_nt2,thue_nt:tien2, thue');
    else v.addGridFields(g, 'gia_nt,tien_nt2,thue_nt:gia,tien2, thue');
    v.addTotalFields(g, [['t_tien_nt2', 'tien_nt2'],['t_tien2', 'tien2'],['t_thue_nt', 'thue_nt'],['t_thue', 'thue']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d23', 'tk_no']&ListTabChange;&PostTabChange;, 'ma_nvbh']);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d23'&ListTabChange;&PostTabChange;, 'ma_nvbh']);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$CreditAccount(o) {o.parentForm.request('CreditAccount', 'CreditAccount', ['tk'], o);}
function onChange$Voucher$TaxCode(o) {o.parentForm.request('GetTaxRate', 'GetTaxRate', ['ma_thue'], o);}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem("d23")._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
  g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      set$Voucher$DefaultValue(f);
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_thue_no', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, &ResetCustInfoFields;);
      f.setItemControlBehavior('ten_khthue', result[4].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[5].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[6].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[7].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_nvbh', result[8].Value, result[9].Value, &ResetCustInfoFields;);
      f.live(f.getItem('ong_ba'));
      break;
    case 'CreditAccount':
      f.setItemControlBehavior('tk_thue_no', result[0].Value, '');
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {if (f._action != 'View') onChange$Voucher$TaxType(f.getItem('invat_yn'), true);}
function onChange$Voucher$TaxType(o, force) {
  var f = o.parentForm, v = (f.getItemValue('invat_yn') == 0);
  setItemDisable(f, 'mau_bc, ma_tc', v);
  setItemAllowNulls(f, 'mau_bc, ma_tc', v);
  setFieldsEmpty(f, 'mau_bc, ma_tc, ten_bc%l, ten_tc%l', !v);
  if (!v) {
    if (!force) f.getItem('mau_bc').focus();
    if (f.getItemValue('mau_bc') == '') f.setItemValue('mau_bc', 3);
    if (f.getItemValue('ma_tc') == '') f.setItemValue('ma_tc', f._propertyTax);
  }
  if (v) {
    f.setReferenceKeyFilter('mau_bc');
    f.setReferenceKeyFilter('ma_tc');
  }
}
function setItemAllowNulls(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    o.field.AllowNulls = v;
  }
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');}
/* </flatten> */
      &ListScript;
      &PostScript;

